   794→#[test]
   795→fn jjtg_rail_move_first() {
   796→    // Test that --first moves to first ACTIONABLE position, not absolute position 0
   797→    let mut gallops = make_valid_gallops();
   798→    let (heat_key, mut heat) = make_valid_heat("AB", "my-heat");
   799→
   800→    // Make the first pace (from make_valid_heat) complete
   801→    let pace1_key = heat.order[0].clone();
   802→    heat.paces.get_mut(&pace1_key).unwrap().tacks[0].state = jjrg_PaceState::Complete;
   803→
   804→    // Add pace2 (complete) and pace3 (rough) and pace4 (rough)
   805→    let pace2_key = "₢ABAAB".to_string();
   806→    let pace3_key = "₢ABAAC".to_string();
   807→    let pace4_key = "₢ABAAD".to_string();
   808→    heat.paces.insert(pace2_key.clone(), jjrg_Pace {
   809→        tacks: vec![make_valid_tack(jjrg_PaceState::Complete, "second-pace", None)],
   810→    });
   811→    heat.paces.insert(pace3_key.clone(), jjrg_Pace {
   812→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "third-pace", None)],
   813→    });
   814→    heat.paces.insert(pace4_key.clone(), jjrg_Pace {
   815→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "fourth-pace", None)],
   816→    });
   817→    heat.order.push(pace2_key.clone());
   818→    heat.order.push(pace3_key.clone());
   819→    heat.order.push(pace4_key.clone());
   820→    heat.next_pace_seed = "AAE".to_string();
   821→
   822→    // Order: [complete1, complete2, rough3, rough4]
   823→    gallops.heats.insert(heat_key.clone(), heat);
   824→
   825→    // Move fourth pace (rough) to first actionable position
   826→    // Should go BEFORE pace3 (first rough), not before pace1 (absolute first)
   827→    let args = jjrg_RailArgs {
