    gallops.heats.insert(key_ab.clone(), heat_ab);
    gallops.heats.insert(key_cd.clone(), heat_cd);
    gallops.heats.insert(key_ef.clone(), heat_ef);

    // Move second heat (CD) to racing - should move to front
    let args = jjrg_FurloughArgs {
